import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

CONTEXT = {
"7": {
"1": "<p>The dedication of the tabernacle altar marks the fulfillment of the instructions in Exodus 25-40. This verse anchors chapter 7 to a specific day: the first day of the first month of the second year after the exodus (cf. Exod 40:17). Numbers 1 begins a month later (Num 1:1), making chapter 7 a chronological flashback embedded within Numbers. The anointings here — tabernacle, altar, and all their vessels — correspond exactly to Exodus 40:9-11. Moses acts as the anointing priest before Aaron takes over the priestly role.</p>",
"2": "<p>The <b>nesiim</b> (princes/leaders) are the same tribal heads appointed in the census (Num 1:4-16). Their role throughout Numbers 1-10 is as community representatives, standing between the tribal masses and the sanctuary. Ancient Near Eastern parallels show regional governors and city-leaders bringing inaugural gifts to newly built temples — the Gudea Cylinder of Lagash (c. 2100 BCE) describes exactly this kind of multi-official dedication gift-giving over successive days.</p>",
"3": "<p>Six covered wagons (<b>agalot tzab</b>) and twelve oxen — one wagon per two leaders, one ox per leader. The wagons are covered, perhaps to protect the tabernacle materials during transport. The gift is presented <b>lifnei YHWH</b> (before YHWH), at the entrance of the tent of meeting, where divine acceptance is the only authorization that matters.</p>",
"4": "<p>YHWH instructs Moses to receive the gifts for use in the service of the tent of meeting. The leader's initiative required divine authorization — the offering was generous but the allocation could not be self-determined. The pattern of human initiative requiring divine disposition recurs throughout the tabernacle/temple traditions.</p>",
"5": "<p>Moses distributes the wagons and oxen according to the carrying duties of each Levitical family. The distribution is not equal — it is functional. Gershon and Merari receive different allocations based on what they actually transport. Equitable distribution serves the work rather than the appearance of fairness.</p>",
"6": "<p>Two wagons and four oxen to the Gershonites (v7) and four wagons and eight oxen to the Merarites (v8). The Gershonites carry the soft goods (curtains, coverings) while the Merarites carry the structural elements (boards, bars, pillars) — the heavier structural load receives more transport resources. This allocation reflects the practical weight difference between fabric and acacia-wood frames.</p>",
"7": "<p>Two wagons and four oxen to Gershon's sons — for their carrying duty. Gershon's portion of tabernacle transport (Num 4:21-28) includes the outermost coverings, curtains, and hangings — substantial in area but less dense than timber framing. The oxen and wagons make the long desert march manageable.</p>",
"8": "<p>Four wagons and eight oxen to Merari's sons — under Ithamar son of Aaron. The Merarites carry the frames, sockets, pillars, and bases of the tabernacle (Num 4:29-33) — the structural skeleton. The heavier allocation corresponds to the heavier load. Ithamar's supervision of both Gershonite and Merarite transport (Num 4:28, 33) makes him the logistics coordinator of tabernacle movement.</p>",
"9": "<p>The Kohathites receive no wagons because their holy objects must be carried by hand on their shoulders. The ark, table, lampstand, altars, and sanctuary vessels are too sacred for wagons — Kohathite service is intensely physical and personal, bodies bearing what cannot be distanced. This principle appears again when David attempts to transport the ark on a wagon (2 Sam 6:3-7) with fatal results: wagon-transport violated the Kohathite rule.</p>",
"10": "<p>The princes offer their dedication gifts for the altar on the day of its anointing — twelve successive days, one leader per day. The word <b>chanukkat</b> (dedication/inauguration) gives the name to the later Feast of Dedication (<em>Hanukkah</em>), though that event is different in kind. The root <em>chanak</em> means to dedicate or initiate something for its intended purpose.</p>",
"11": "<p>YHWH designates one leader per day, tribe by tribe. The structure is deliberately egalitarian: no tribe presents simultaneously with another, each receiving its own day and its own moment of presentation before YHWH. The ordering follows Numbers 2's camp arrangement — Judah leads, corresponding to Judah's lead position in the marching order.</p>",
"12": "<p>Day 1: Nahshon son of Amminadab for Judah. Nahshon appears in Ruth 4:20 and Matthew 1:4 — he stands in the direct messianic line. His name may relate to <em>nachash</em> (serpent/diviner), a theophoric element common in Bronze Age Semitic names. His offering is presented as the pattern; the eleven repetitions that follow echo it exactly.</p>",
"13": "<p>The silver dish weighs 130 shekels, the silver basin 70 shekels — both filled with fine flour mixed with oil for a grain offering. The <b>qe'arah</b> (dish/plate — from a root meaning to scrape or hollow out) is a flat vessel; the <b>mizraq</b> (basin/bowl — from <em>zaraq</em>, to sprinkle) is used elsewhere for sprinkling blood at the altar (Exod 27:3). The two vessels together cover both grain presentation and blood-sprinkling functions.</p>",
"14": "<p>One gold pan (<b>kaph</b> — palm of the hand) weighing 10 shekels, filled with incense. The gold pan is small — the kaph is literally a palm-cup, just large enough to hold incense. Its gold composition distinguishes it from the silver vessels. Incense offerings belong to the realm of pleasing aroma and divine presence: the smoke ascends. The incense altar stood inside the tabernacle (Exod 30), but the pan carries incense for the altar dedication.</p>",
"15": "<p>The burnt offering: one young bull, one ram, one male lamb a year old. The three-animal burnt offering (bull, ram, lamb) represents the full range of herd and flock offerings — a comprehensive gift of dedication. <b>Olah</b> (burnt offering — the whole-ascent offering) signals total consecration: the entire animal goes up to YHWH, nothing reserved for the offerer.</p>",
"16": "<p>One male goat for a sin offering (<b>chatat</b>). The sin offering accompanies every major dedication and feast (Num 28-29). Even the most exalted dedication ceremony begins with the acknowledgment of sin's presence. No approach to the holy is without the sin offering's recognition that the offerer comes as a sinner.</p>",
"17": "<p>Peace offerings (<b>shelamim</b>): two oxen, five rams, five male goats, five male lambs a year old. The peace offering's shared consumption (priest, offerer, family) creates a communal meal in YHWH's presence. The large quantities — oxen, five of each smaller animal — signal celebration. This is Nahshon's offering. The same pattern repeats for all twelve leaders.</p>",
"18": "<p>Day 2: Nethanel son of Zuar for Issachar. Nethanel means 'God has given' — a theophoric name carrying gratitude. Issachar's blessing (Gen 49:14-15) speaks of bearing loads and finding rest in good land; the tribe's carrying of this offering echoes the blessing's labor motif. The offering is identical to Nahshon's in every detail.</p>",
"19": "<p>Nethanel's silver dish (130 shekels) and silver basin (70 shekels), both filled with fine flour and oil. The repetition of exact weights and contents across all twelve days is significant: no tribe can claim to have given more to YHWH's service. Equality before the altar is built into the structure of the dedication ritual.</p>",
"20": "<p>The gold pan of 10 shekels filled with incense — identical to Nahshon's (v14). Twelve pans, twelve tribes, one weight. The incense offering to YHWH is not a matter of status or wealth but of identical access and identical devotion.</p>",
"21": "<p>Nethanel's burnt offering: one young bull, one ram, one male lamb a year old. The three-part olah is constant across all twelve days. The burnt offering's constancy signals that total consecration to YHWH is the same act regardless of which tribe performs it.</p>",
"22": "<p>One male goat for the chatat (sin offering). The sin offering does not vary. The theological message: all twelve tribes stand equally in need of atonement, and all twelve receive the same provision for it. No tribe's guilt before YHWH is lesser than another's.</p>",
"23": "<p>Nethanel's peace offerings: two oxen, five rams, five male goats, five male lambs a year old. The peace offering closes the twelve-day pattern for each tribe with celebration. From sin offering to burnt offering to peace — the ritual sequence moves from atonement to dedication to communion.</p>",
"24": "<p>Day 3: Eliab son of Helon for Zebulun. Zebulun's territory later encompasses the northern Galilee (Josh 19:10-16), the region Isaiah identifies as 'land of Zebulun and land of Naphtali' where 'the people who walked in darkness have seen a great light' (Isa 9:1-2), fulfilled in Jesus's ministry (Matt 4:13-16). Zebulun brings its offering with the same dignity as Judah.</p>",
"25": "<p>Eliab's silver vessels: dish of 130 shekels and basin of 70 shekels, filled with grain offering. The <b>solet</b> (fine flour) and <b>shemen</b> (oil) represent agricultural wealth transformed into devotion. The finest of the crop — not leftovers — is what fills these vessels.</p>",
"26": "<p>The gold incense pan of 10 shekels. Day 3's incense offering ascends like days 1 and 2, and like all twelve that follow. The cumulative effect: twelve plumes of incense smoke over twelve days, the aroma of twelve tribes' devotion filling the newly dedicated sanctuary space.</p>",
"27": "<p>Zebulun's burnt offering: bull, ram, lamb. The olah's three-fold structure — large animal (herd), medium (flock), small (flock) — spans the full range of domesticated offering animals. This comprehensiveness is itself a statement: the whole created order of domesticated life is offered back to its Creator.</p>",
"28": "<p>The goat sin offering — universal across all twelve presentations. In a chapter of enormous variety of names and tribes, the sin offering is the great equalizer. The same single goat for each tribe acknowledges that before YHWH's altar, every tribe's moral situation is identical.</p>",
"29": "<p>Zebulun's peace offerings: two oxen, five rams, five goats, five lambs. The five-five-five pattern in the smaller animals may have had a numerical significance — fives in the ANE were often associated with completeness in gift-lists. Whether intentional or conventional, the effect is a generous communal meal.</p>",
"30": "<p>Day 4: Elizur son of Shedeur for Reuben. Reuben was Jacob's firstborn, who lost the birthright through moral failure (Gen 35:22; 49:3-4). Yet here Reuben's leader brings the identical offering — no diminishment, no reduced honor at the altar. The altar equalizes tribal status derived from birth order and history.</p>",
"31": "<p>Elizur's silver dish and basin. Reuben means 'see, a son' (<em>re'u-ben</em>) — a name of maternal hope. The offering is not freighted with the tribe's complicated history but presented simply as the tribe's gift to YHWH.</p>",
"32": "<p>The gold incense pan. On day 4 as on day 1, incense rises from the same-weight vessel. The dedication does not accelerate or slow; the rhythm is steady, one tribe per day, the smoke ascending.</p>",
"33": "<p>Reuben's burnt offering: bull, ram, lamb a year old. The one-year-old lamb (<em>kebes ben-shanah</em>) is the standard age requirement for purity and completeness in offerings — in the prime of life, unblemished. The offering is at its best.</p>",
"34": "<p>One goat for the sin offering for Reuben, as for every tribe. The sin offering's constancy across all twelve days is a structural theological statement: the dedication of the altar does not bypass the need for atonement; it establishes the mechanism through which atonement continues.</p>",
"35": "<p>Reuben's peace offerings: two oxen, five rams, five goats, five lambs. Elizur's offering for Reuben is complete — the full sequence from sin to ascent to communion, the same as all eleven other tribes. Numbers 7 insists on this equality with deliberate, exhaustive repetition.</p>",
"36": "<p>Day 5: Shelumiel son of Zurishaddai for Simeon. Simeon and Levi had been cursed for violence at Shechem (Gen 34; 49:5-7): 'scattered in Israel.' The Levites found their scattering transformed into priestly vocation; Simeon was absorbed into Judah's territory. Yet here Simeon stands with a full offering, indistinguishable from the tribes whose futures shone brighter.</p>",
"37": "<p>Shelumiel's silver vessels: dish and basin of standard weights. The name Shelumiel contains <em>shalom</em> (peace) — 'my peace is God.' The offering of the Simeonite leader carries peace in its name even as the tribe's history carried violence.</p>",
"38": "<p>The gold incense pan for Simeon. Incense offering is an act of the will — it requires no special tribal status, only the decision to approach YHWH with what has been prescribed. Simeon's pan burns alongside Judah's and Issachar's.</p>",
"39": "<p>Simeon's burnt offering: bull, ram, lamb. The olah for Simeon is total consecration. The altar receives Simeon's best animals as it received every tribe's best — the offering mechanism does not know tribal reputation, only obedience.</p>",
"40": "<p>The goat sin offering for Simeon. The same animal, the same atoning function. Before the altar, the tribe of Shechem's avengers and the tribe of the messianic line both present a single goat and receive the same provision.</p>",
"41": "<p>Simeon's peace offerings: two oxen, five rams, five goats, five lambs. The peace offering closes five days of dedication. The cumulative totals are growing: five bulls, five rams, five lambs burned entirely; five goats for sin; ten oxen plus five rams, goats, and lambs for communion — the altar is fed richly for twelve days.</p>",
"42": "<p>Day 6: Eliasaph son of Deuel for Gad. Gad settled east of the Jordan (Num 32) — a pragmatic choice that would mark the tribe as somewhat peripheral in later Israelite life. Yet on this day of altar dedication, Gad's leader stands with the same offering as Judah's. Geography determines territory; the altar knows only the offering.</p>",
"43": "<p>Eliasaph's silver dish and basin. Eliasaph ('my God has added') carries a name of divine abundance. The silver vessels — 130 and 70 shekels — represent significant wealth. The 200-shekel total of silver per tribe across twelve days amounts to 2,400 shekels total. The dedication was economically substantial, not merely symbolic.</p>",
"44": "<p>The gold incense pan of 10 shekels. Ten shekels of gold was a significant gift — a ring of 10 gold shekels was itself a large piece of jewelry (cf. Gen 24:22, a ring of a half-shekel). The incense pan carries real monetary value concentrated in a small, purposeful form.</p>",
"45": "<p>Gad's burnt offering: bull, ram, lamb. Gad means 'good fortune' or 'a troop comes' (Gen 30:11; 49:19) — a warrior-tribe's name. The offering transforms martial energy into devotion: the same strength that produces soldiers produces the bull, ram, and lamb brought before YHWH.</p>",
"46": "<p>The goat sin offering. Six tribes have now brought their sin offerings — six goats consumed, six tribes acknowledged as in need of atonement. The regularity is pastoral wisdom: the leadership of Israel ritually acknowledging corporate need for covering was built into the calendar from day one.</p>",
"47": "<p>Gad's peace offerings: two oxen, five rams, five goats, five lambs. Halfway through the twelve days. Six tribes have spoken through their offerings. The altar dedication is thorough, tribe by tribe, no shortcut.</p>",
"48": "<p>Day 7: Elishama son of Ammihud for Ephraim. Ephraim — the younger of Joseph's two sons, blessed ahead of his brother Manasseh by Jacob (Gen 48:14-20) — represents the overturned expectations that run through Genesis. The tribe of Ephraim dominates the central highlands and gives its name to the northern kingdom. Its leader stands on day 7 with the same gift as day 1.</p>",
"49": "<p>Elishama's silver dish and basin. Ephraim's offering is identical to Judah's, Reuben's, and every other tribe's. The preferential blessing Jacob gave Joseph and Ephraim (Gen 48) does not translate into a larger offering before YHWH. At the altar, election brings responsibility, not privilege of quantity.</p>",
"50": "<p>The gold incense pan for Ephraim. Seven days of incense now — a full week of dedication. The seventh-day resonance may be intentional: the altar dedication mirrors creation's seven-day structure, the first week of Edenic completeness echoed in the first week of tabernacle worship.</p>",
"51": "<p>Ephraim's burnt offering: bull, ram, lamb. The same three-animal olah as every other tribe. Ephraim's dominance in the northern kingdom (later 'Ephraim' as a metonym for Israel in Hosea) is decades in the future; today the tribe is one of twelve equal offerers.</p>",
"52": "<p>The goat sin offering for Ephraim. Seven goats over seven days. The sin offering for the people's leadership is now complete for a full week — a weekly rhythm of atonement for the nation's representatives will become institutionalized in the festival calendar (Num 28-29).</p>",
"53": "<p>Ephraim's peace offerings: two oxen, five rams, five goats, five lambs. The peace offering of communal celebration closes week one. Halfway through the dedication, the altar has received: seven full burnt offerings, seven sin offerings, seven peace-offering sets. The theology of completeness is embedded in the numbers.</p>",
"54": "<p>Day 8: Gamaliel son of Pedahzur for Manasseh. Manasseh — the elder of Joseph's sons, demoted by Jacob's crossing of hands (Gen 48:14) — leads Ephraim's sibling tribe. The reversal of primogeniture does not diminish Manasseh's place in the altar dedication. Both Joseph-tribes present identical offerings, the blessing's complexity invisible in the offering's equality.</p>",
"55": "<p>Gamaliel's silver vessels. Manasseh's tribe was split: half settled west of Jordan in the central highlands, half east (Num 32). The offering is a single act for a single tribe, regardless of its later geographical division. The altar dedication knows the tribe before its partition.</p>",
"56": "<p>The gold incense pan for Manasseh. Eight days of rising incense. The aroma of dedication builds over the twelve days — not a single dramatic act but a cumulative, patient consecration of the altar through repeated offering.</p>",
"57": "<p>Manasseh's burnt offering: bull, ram, lamb. The sacrificial formula is fixed. The fixity is itself pastoral: the offerer need not wonder what to bring. YHWH has specified the gift; the act of obedience — bringing what was commanded — is the offering. The creativity of worship lies not in inventing new forms but in faithfully embodying prescribed ones.</p>",
"58": "<p>The goat sin offering for Manasseh. Day 8 echoes days 1-7 in the sin-offering slot. The altar's dedication does not reach a point where sin's acknowledgment becomes unnecessary — each day renews the same starting position before YHWH.</p>",
"59": "<p>Manasseh's peace offerings: two oxen, five rams, five goats, five lambs. Nine tribes have offered; three remain. The peace offerings pile up in the altar's ledger — a cumulative theology of communion, YHWH feasting with his people through their representatives.</p>",
"60": "<p>Day 9: Abidan son of Gideoni for Benjamin. Benjamin — youngest son of Jacob, child of Rachel's death (Gen 35:18; she named him Ben-oni, 'son of my sorrow'), renamed Benjamin ('son of the right hand') by Jacob — holds a complex identity. The tribe that gave Israel its first king (Saul) and the apostle Paul (Phil 3:5) stands here as a young tribe bringing an ancient offering.</p>",
"61": "<p>Abidan's silver dish and basin. Benjamin's offering is the same as the ten tribes before him. The right-hand status conferred by Jacob's renaming does not enlarge the offering; the altar honors obedience over etymological privilege.</p>",
"62": "<p>The gold incense pan for Benjamin. Nine days of incense. The accumulated prayers and dedication of nine tribes' leaders have preceded this moment — Benjamin enters a space already thick with the aroma of devotion.</p>",
"63": "<p>Benjamin's burnt offering: bull, ram, lamb. The third-to-last burnt offering of the dedication. The chapter is drawing toward its close — three more days and the twelve-tribe dedication will be complete. The altar will have been dedicated by all Israel, not just the dominant tribes.</p>",
"64": "<p>The goat sin offering for Benjamin. Each tribe acknowledges before YHWH: we come with sin; we need covering. No tribe, not even the one that produced the first king, bypasses this acknowledgment. The sin offering is democracy of the deepest kind.</p>",
"65": "<p>Benjamin's peace offerings: two oxen, five rams, five goats, five lambs. Benjamin's feast-offering joins the growing communion. Nine tribal dedication celebrations concluded; three remain.</p>",
"66": "<p>Day 10: Ahiezer son of Ammishaddai for Dan. Dan — the tribe of the judge Samson (Judg 13-16) and the tribe that migrated north to establish a rival shrine (Judg 18) — presents here without hint of future apostasy. The altar dedication precedes the stories of failure; it establishes the norm against which deviation will later be measured.</p>",
"67": "<p>Ahiezer's silver vessels. Dan's offering: identical to all before. The northern migration and the Danite shrine (Judg 18:30-31) are still decades in the future. Here the tribe participates in the legitimate central sanctuary's founding dedication.</p>",
"68": "<p>The gold incense pan for Dan. Ten days of incense. The number carries weight in the Decalogue — ten commandments, ten days of dedication, ten silver shekels per pan across the decade. Ten is a number of completeness in Israel's symbolic vocabulary.</p>",
"69": "<p>Dan's burnt offering: bull, ram, lamb. The olah rises on day 10 as on days 1-9. The repetition is the point — the altar dedication is not a single dramatic moment but a sustained, multi-day, all-tribal act of worship. Durability of consecration, not intensity of a single moment, is what the structure celebrates.</p>",
"70": "<p>The goat sin offering for Dan. Day 10's acknowledgment of corporate sin. Dan's future failures (Judg 17-18) do not exempt the tribe from beginning at the altar in the right posture. The sin offering does not guarantee fidelity but it establishes the only honest starting point.</p>",
"71": "<p>Dan's peace offerings: two oxen, five rams, five goats, five lambs. Ten days of communion offerings. The altar is becoming, through these twelve days, a place of communal memory and shared participation for all Israel.</p>",
"72": "<p>Day 11: Pagiel son of Ochran for Asher. Asher — whose blessing from Jacob spoke of fat bread and royal delicacies (Gen 49:20) — settled in the fertile Galilee coastal plain. The tribe that Anna the prophetess comes from (Luke 2:36), who recognized the infant Jesus in the temple, connects these distant offerings to the one to whom all offerings point.</p>",
"73": "<p>Pagiel's silver dish and basin. Asher's offering is the same standard gift. The tribe of agricultural abundance and royal food does not offer more than the other tribes — the altar's economy is not the economy of royal feasting. All present the same gift to the same YHWH.</p>",
"74": "<p>The gold incense pan for Asher. Eleven days of incense before the final day. The cumulative smoke of eleven tribes' dedication has risen; one more will complete the picture of all Israel gathered, represented, dedicated.</p>",
"75": "<p>Asher's burnt offering: bull, ram, lamb. The penultimate olah. Tomorrow Naphtali will complete the twelve-tribe dedication with the same three animals. The burnt offering is whole and ascending — a picture of total devotion that will not be exhausted by repetition.</p>",
"76": "<p>The goat sin offering for Asher. Day 11's acknowledgment. The sin offering is both backward-looking (acknowledging accumulated sin) and forward-looking (establishing the mechanism for ongoing atonement). It is not a one-time reset but a recurring posture.</p>",
"77": "<p>Asher's peace offerings: two oxen, five rams, five goats, five lambs. Eleven tribal feasts of communion with YHWH. The peace offering (<em>shelamim</em>) roots are the same as <em>shalom</em> — wholeness, welfare, completeness. The feast-offering embodies the state it names.</p>",
"78": "<p>Day 12: Ahira son of Enan for Naphtali. Naphtali — whose territory encompassed the northern shore of the Sea of Galilee, whom Isaiah marked as a land of darkness that would see great light (Isa 9:1-2, fulfilled in Matt 4:13-16) — closes the twelve-tribe dedication. The last to offer is not diminished; the twelfth day is equal to the first.</p>",
"79": "<p>Ahira's silver dish and basin. The final pair of silver vessels. Twelve dishes, twelve basins — 1,560 and 840 shekels of silver respectively, totaling 2,400 shekels (v84 confirms). The accumulated weight of the dedication in silver is massive; the accumulated devotion it represents is immeasurable.</p>",
"80": "<p>The gold incense pan for Naphtali. The twelfth and final pan. Twelve pans of gold (v86 confirms 120 shekels total), twelve plumes of incense, twelve tribes' prayer ascending over twelve days. The dedication is aromatic as well as bloody — incense and burnt offering together fill the sanctuary space with the presence of all Israel's worship.</p>",
"81": "<p>Naphtali's burnt offering: bull, ram, lamb. The twelfth and final olah of the dedication series. The last ascending whole-burnt-offering of the twelve-day ceremony closes the cycle. Total burnt offerings: twelve bulls, twelve rams, twelve male lambs — the full herd and flock of a whole nation offered.</p>",
"82": "<p>The goat sin offering for Naphtali. The twelfth and final chatat of the dedication. Twelve tribes, twelve acknowledgments of sin, twelve goats consumed. The altar begins its permanent ministry with this foundation: atonement for all Israel, tribe by tribe, before anything else.</p>",
"83": "<p>Naphtali's peace offerings: two oxen, five rams, five goats, five lambs. The final communal feast. With this verse the twelve-day dedication series is complete — every tribe has spoken through its leader, every offering type has been repeated twelve times, and the altar has received the gifts of the whole nation.</p>",
"84": "<p>The dedication totals for the altar: twelve silver dishes, twelve silver basins, twelve gold pans. The summary now consolidates what the twelve repetitions built. <b>Chanukkat hamizbe'ach</b> — the dedication of the altar — is complete as a whole, not just as twelve individual acts. The summary restates the gift as Israel's collective offering.</p>",
"85": "<p>Each silver dish 130 shekels, each basin 70 shekels: total silver of the vessels 2,400 shekels by the shekel of the sanctuary. The <b>shekel hakodesh</b> (sanctuary shekel) is the standard weight unit for sacred offerings — heavier than the commercial shekel, ensuring the holy gifts were measured by a stricter standard. All valuations in the sanctuary use this weight.</p>",
"86": "<p>Twelve gold pans, each 10 shekels by the sanctuary shekel: 120 shekels total, filled with incense. The twelve incense pans sum to a single gift of 120 shekels of gold — a significant quantity. The number 120 appears at significant points in biblical narrative: Moses's age at death, the 120 in the upper room at Pentecost (Acts 1:15), Ezra's returnees. The dedication gold anchors a number that becomes associated with the threshold of new beginnings.</p>",
"87": "<p>The burnt offerings total: twelve bulls, twelve rams, twelve male lambs a year old with their grain offerings, and twelve male goats for sin offerings. The summary converts the twelve repeated sequences into a single collective offering. The full burnt offering total (twelve of each animal) represents Israel's total consecration as one people.</p>",
"88": "<p>The peace offerings total: twenty-four bulls, sixty rams, sixty male goats, sixty male lambs. The large numbers reflect the communal feast scale: the twelve peace-offering sets together provided meat for widespread celebration. The dedication feast was not intimate but national — a feast of all Israel in YHWH's presence at the altar's inauguration.</p>",
"89": "<p>Moses enters the tent of meeting to speak with YHWH — and he hears the voice speaking to him from above the <b>kapporet</b> (covering/mercy seat) between the two cherubim on the ark of testimony. This verse is the theological payoff of the entire chapter. Twelve days of offerings, twelve leaders' gifts, all the silver and gold and animals — culminating in a moment of divine communication. The kapporet (<em>from kapar</em>, to cover/atone) is the cover of the ark where YHWH promised to meet Moses (Exod 25:22). The voice comes from between the cherubim: the same throne-chariot imagery that appears in Ezekiel 1 and Isaiah 6. All Israel's offering creates the context for one man's encounter with the living God speaking from within the holy of holies.</p>"
}
}

comm = load_comm('mkt-context', 'numbers')
merge_comm(comm, CONTEXT)
save_comm('mkt-context', 'numbers', comm)
print('Numbers 7 mkt-context written.')
